+import Foundation
+import LLM
+
+@MainActor
+protocol CleanupRuntimeLoading: AnyObject {
+    func download(
+        _ model: CleanupModelDescriptor,
+        to directory: URL,
+        progress: @escaping @MainActor @Sendable (Double) -> Void
+    ) async throws -> URL
+
+    func initialize(_ request: CleanupInitializationRequest) async throws
+    func reset()
+}
+
+@MainActor
+final class CleanupModelLoader: CleanupModelLoading {
+    private let runtime: any CleanupRuntimeLoading
+    private let fileManager: FileManager
+    private let cleanupModelsRootURL: URL
+
+    init(
+        runtime: any CleanupRuntimeLoading = CleanupRuntimeBridge(),
+        fileManager: FileManager = .default,
+        cleanupModelsRootURL: URL? = nil
+    ) {
+        self.runtime = runtime
+        self.fileManager = fileManager
+        self.cleanupModelsRootURL = cleanupModelsRootURL ?? AppSupportPaths.cleanupModelsRootURL(fileManager: fileManager)
+    }
+
+    func isCached(_ model: CleanupModelDescriptor) async throws -> Bool {
+        fileManager.fileExists(atPath: canonicalModelURL(for: model).path)
+    }
+
+    func download(_ model: CleanupModelDescriptor, progress: @escaping @MainActor @Sendable (Double) -> Void) async throws {
+        try ensureDirectoryExists(at: cleanupModelsRootURL)
+
+        let downloadedURL = try await runtime.download(
+            model,
+            to: cleanupModelsRootURL,
+            progress: progress
+        )
+
+        _ = try activateDownloadedModel(at: downloadedURL, for: model)
+    }
+
+    func load(_ model: CleanupModelDescriptor) async throws {
+        let modelURL = canonicalModelURL(for: model)
+        guard fileManager.fileExists(atPath: modelURL.path) else {
+            throw CleanupModelLoaderError.modelFilesMissing(modelURL.path)
+        }
+
+        try await runtime.initialize(
+            CleanupInitializationRequest(
+                modelID: model.id,
+                modelURL: modelURL,
+                maxTokenCount: model.maxTokenCount,
+                temperature: 0.1,
+                systemPrompt: SettingsStore.defaultCleanupPrompt,
+                thinkingMode: .suppressed
+            )
+        )
+    }
+
+    func resetLoadedModels() async {
+        runtime.reset()
+    }
+
+    private func activateDownloadedModel(at downloadedURL: URL, for model: CleanupModelDescriptor) throws -> URL {
+        let canonicalURL = canonicalModelURL(for: model)
+        try ensureDirectoryExists(at: canonicalURL.deletingLastPathComponent())
+
+        if canonicalURL.standardizedFileURL == downloadedURL.standardizedFileURL {
+            return canonicalURL
+        }
+
+        if fileManager.fileExists(atPath: canonicalURL.path) {
+            return canonicalURL
+        }
+
+        guard fileManager.fileExists(atPath: downloadedURL.path) else {
+            throw CleanupModelLoaderError.modelFilesMissing(downloadedURL.path)
+        }
+
+        try fileManager.moveItem(at: downloadedURL, to: canonicalURL)
+        return canonicalURL
+    }
+
+    private func canonicalModelURL(for model: CleanupModelDescriptor) -> URL {
+        cleanupModelsRootURL.appending(path: model.fileName, directoryHint: .notDirectory)
+    }
+
+    private func ensureDirectoryExists(at url: URL) throws {
+        try fileManager.createDirectory(at: url, withIntermediateDirectories: true)
+    }
+}
+
+@MainActor
+final class CleanupRuntimeBridge: CleanupRuntimeLoading {
+    private var llm: LLM?
+    private var defaultThinkingMode: ThinkingMode = .suppressed
+
+    func download(
+        _ model: CleanupModelDescriptor,
+        to directory: URL,
+        progress: @escaping @MainActor @Sendable (Double) -> Void
+    ) async throws -> URL {
+        let huggingFaceModel = HuggingFaceModel(
+            model.huggingFaceRepository,
+            .Q4_K_M
+        )
+
+        return try await huggingFaceModel.download(
+            to: directory,
+            as: model.fileName,
+            { value in
+                Task { @MainActor in
+                    progress(value)
+                }
+            }
+        )
+    }
+
+    func initialize(_ request: CleanupInitializationRequest) async throws {
+        guard let llm = LLM(
+            from: request.modelURL,
+            template: .qwen(request.systemPrompt),
+            temp: request.temperature,
+            maxTokenCount: request.maxTokenCount
+        ) else {
+            throw CleanupModelLoaderError.initializationFailed(request.modelURL.path)
+        }
+
+        self.llm = llm
+        defaultThinkingMode = thinkingMode(for: request.thinkingMode)
+    }
+
+    func reset() {
+        llm = nil
+        LLM.shutdownBackend()
+    }
+
+    private func thinkingMode(for mode: CleanupThinkingMode) -> ThinkingMode {
+        switch mode {
+        case .suppressed:
+            return .suppressed
+        }
+    }
+}
+
+private enum CleanupModelLoaderError: LocalizedError {
+    case modelFilesMissing(String)
+    case initializationFailed(String)
+
+    var errorDescription: String? {
+        switch self {
+        case let .modelFilesMissing(path):
+            return "Cleanup model files are missing at \(path)."
+        case let .initializationFailed(path):
+            return "Cleanup model initialization failed for \(path)."
+        }
+    }
+}

