+import Foundation
+import Observation
+
+enum CleanupThinkingMode: Equatable, Sendable {
+    case suppressed
+}
+
+struct CleanupInitializationRequest: Equatable, Sendable {
+    var modelID: String
+    var modelURL: URL
+    var maxTokenCount: Int32
+    var temperature: Float
+    var systemPrompt: String
+    var thinkingMode: CleanupThinkingMode
+}
+
+struct CleanupModelDescriptor: Equatable, Sendable {
+    var id: String
+    var parameterCountLabel: String
+    var approximateSizeLabel: String
+    var maxTokenCount: Int32
+    var speedLabel: String
+    var fileName: String
+    var huggingFaceRepository: String
+
+    static let qwenZeroPointEightB = CleanupModelDescriptor(
+        id: "qwen35_0_8b_q4_k_m",
+        parameterCountLabel: "0.8B",
+        approximateSizeLabel: "~535 MB",
+        maxTokenCount: 2048,
+        speedLabel: "Very fast",
+        fileName: "Qwen3.5-0.8B-Q4_K_M.gguf",
+        huggingFaceRepository: "unsloth/Qwen3.5-0.8B-GGUF"
+    )
+
+    static let qwenTwoB = CleanupModelDescriptor(
+        id: "qwen35_2b_q4_k_m",
+        parameterCountLabel: "2B",
+        approximateSizeLabel: "~1.3 GB",
+        maxTokenCount: 2048,
+        speedLabel: "Fast",
+        fileName: "Qwen3.5-2B-Q4_K_M.gguf",
+        huggingFaceRepository: "unsloth/Qwen3.5-2B-GGUF"
+    )
+
+    static let qwenFourB = CleanupModelDescriptor(
+        id: "qwen35_4b_q4_k_m",
+        parameterCountLabel: "4B",
+        approximateSizeLabel: "~2.8 GB",
+        maxTokenCount: 4096,
+        speedLabel: "Full",
+        fileName: "Qwen3.5-4B-Q4_K_M.gguf",
+        huggingFaceRepository: "unsloth/Qwen3.5-4B-GGUF"
+    )
+
+    static let `default` = qwenZeroPointEightB
+
+    static let catalog = [
+        qwenZeroPointEightB,
+        qwenTwoB,
+        qwenFourB
+    ]
+}
+
+extension CleanupModelDescriptor {
+    static func catalogEntry(id: String) -> CleanupModelDescriptor? {
+        catalog.first { $0.id == id }
+    }
+}
+
+@MainActor
+protocol CleanupModelLoading: AnyObject {
+    func isCached(_ model: CleanupModelDescriptor) async throws -> Bool
+    func download(_ model: CleanupModelDescriptor, progress: @escaping @MainActor @Sendable (Double) -> Void) async throws
+    func load(_ model: CleanupModelDescriptor) async throws
+    func resetLoadedModels() async
+}
+
+@MainActor
+protocol CleanupModelManaging: AnyObject {
+    var phase: CleanupModelManager.Phase { get }
+    var errorMessage: String? { get }
+    var downloadProgress: Double? { get }
+    var loadedModelID: String? { get }
+    var cachedModelIDs: Set<String> { get }
+
+    func load(modelID: String?) async
+    func refreshCachedModelIDs() async
+    func shutdown() async
+}
+
+@MainActor
+final class NoOpCleanupModelManager: CleanupModelManaging {
+    var phase: CleanupModelManager.Phase = .idle
+    var errorMessage: String?
+    var downloadProgress: Double?
+    var loadedModelID: String?
+    var cachedModelIDs: Set<String> = []
+
+    func load(modelID: String?) async {
+        _ = modelID
+    }
+
+    func refreshCachedModelIDs() async {
+    }
+
+    func shutdown() async {
+    }
+}
+
+@MainActor
+@Observable
+final class CleanupModelManager {
+    enum Phase: Equatable {
+        case idle
+        case downloading
+        case loading
+        case ready
+        case error
+    }
+
+    private let catalog: [CleanupModelDescriptor]
+    private let catalogByID: [String: CleanupModelDescriptor]
+    private let loader: any CleanupModelLoading
+    private let configuredModelIDProvider: @MainActor () -> String?
+    private let availabilityOverrideProvider: @MainActor () -> Bool
+
+    private(set) var phase: Phase = .idle
+    private(set) var errorMessage: String?
+    private(set) var downloadProgress: Double?
+    private(set) var loadedModelID: String?
+    private(set) var cachedModelIDs: Set<String> = []
+
+    init(
+        catalog: [CleanupModelDescriptor],
+        loader: any CleanupModelLoading,
+        configuredModelIDProvider: @escaping @MainActor () -> String? = { nil },
+        availabilityOverrideProvider: @escaping @MainActor () -> Bool = { true }
+    ) {
+        self.catalog = catalog
+        catalogByID = Dictionary(uniqueKeysWithValues: catalog.map { ($0.id, $0) })
+        self.loader = loader
+        self.configuredModelIDProvider = configuredModelIDProvider
+        self.availabilityOverrideProvider = availabilityOverrideProvider
+    }
+
+    func load(modelID: String?) async {
+        let requestedModel = resolvedModel(for: modelID)
+        await waitForInFlightLoadIfNeeded(requestedModelID: requestedModel.id)
+
+        if phase == .ready, loadedModelID == requestedModel.id {
+            return
+        }
+
+        if phase == .ready, loadedModelID != requestedModel.id {
+            await resetLoadedState()
+        }
+
+        guard availabilityOverrideProvider() else {
+            phase = .error
+            errorMessage = "Cleanup model unavailable."
+            downloadProgress = nil
+            return
+        }
+
+        errorMessage = nil
+        downloadProgress = nil
+
+        do {
+            if try await !loader.isCached(requestedModel) {
+                phase = .downloading
+                try await loader.download(requestedModel) { [weak self] progress in
+                    self?.downloadProgress = progress
+                }
+            }
+
+            downloadProgress = nil
+            phase = .loading
+            try await loader.load(requestedModel)
+            loadedModelID = requestedModel.id
+            cachedModelIDs.insert(requestedModel.id)
+            phase = .ready
+        } catch {
+            phase = .error
+            errorMessage = error.localizedDescription
+        }
+    }
+
+    func refreshCachedModelIDs() async {
+        var refreshedCache: Set<String> = []
+
+        for model in catalog {
+            if (try? await loader.isCached(model)) == true {
+                refreshedCache.insert(model.id)
+            }
+        }
+
+        cachedModelIDs = refreshedCache
+    }
+
+    func unload() async {
+        await resetLoadedState()
+    }
+
+    func shutdown() async {
+        await resetLoadedState()
+    }
+
+    private func resolvedModel(for requestedModelID: String?) -> CleanupModelDescriptor {
+        if
+            let requestedModelID,
+            let model = catalogByID[requestedModelID]
+        {
+            return model
+        }
+
+        if
+            let configuredModelID = configuredModelIDProvider(),
+            let model = catalogByID[configuredModelID]
+        {
+            return model
+        }
+
+        return .default
+    }
+
+    private func waitForInFlightLoadIfNeeded(requestedModelID: String) async {
+        while phase == .downloading || phase == .loading {
+            try? await Task.sleep(nanoseconds: 10_000_000)
+        }
+
+        if phase == .ready, loadedModelID == requestedModelID {
+            return
+        }
+    }
+
+    private func resetLoadedState() async {
+        await loader.resetLoadedModels()
+        loadedModelID = nil
+        downloadProgress = nil
+        errorMessage = nil
+        phase = .idle
+    }
+}
+
+extension CleanupModelManager: CleanupModelManaging {
+}

